custom_css:
@import url('https://fonts.googleapis.com/css2?family=DynaPuff:wght@400..700&family=Roboto:ital,wght@0,100..900&display=swap');

:root {
  --custom-theme-style-inputs: [
  {
    "type": "color",
    "varId": "DarkPurple",
    "displayText": "Dark grey",
    "default": "rgba(49, 50, 68, 1)"
  },
  {
    "type": "color",
    "varId": "MidPurple",
    "displayText": "Med. grey",
    "default": "rgba(88, 91, 112, 1)"
  },
  {
    "type": "select",
    "varId": "customQR-Position",
    "displayText": "QR Button position",
    "default": "flex-end",
    "options": [
      {
        "label": "Left",
        "value": "flex-start"
      },
      {
        "label": "Center",
        "value": "center"
      },
      {
        "label": "Right",
        "value": "flex-end"
      }
    ]
  },
  {
    "type": "select",
    "varId": "headerFont",
    "displayText": "Header font",
    "default": "'DynaPuff', system-ui",
    "options": [
      {
        "label": "DynaPuff",
        "value": "'DynaPuff', system-ui"
      },
      {
        "label": "Default",
        "value": "'Noto Sans', sans-serif"
      }
    ]
  },
  {
    "type": "select",
    "varId": "mainFont",
    "displayText": "Main body font",
    "default": "'Roboto', sans-serif",
    "options": [
      {
        "label": "Roboto",
        "value": "'Roboto', sans-serif"
      },
      {
        "label": "Default",
        "value": "'Noto Sans', sans-serif"
      }
    ]
  },
  {
    "type": "slider",
    "varId": "borderSize",
    "displayText": "Avatar border size",
    "default": "3",
    "min": 0,
    "max": 8,
    "step": 1
  },
  {
    "type": "select",
    "varId": "avatarFrame",
    "displayText": "Avatar frame color",
    "default": "#f5c2e7, #f38ba8, #eba0ac, #fab387, #f9e2af, #a6e3a1, #94e2d5, #89dceb, #74c7ec, #89b4fa, #b4befe, #cba6f7, #f5c2e7",
    "options": [
      {
        "label": "Rainbow",
        "value": "#f5c2e7, #f38ba8, #eba0ac, #fab387, #f9e2af, #a6e3a1, #94e2d5, #89dceb, #74c7ec, #89b4fa, #b4befe, #cba6f7, #f5c2e7"
      },
      {
        "label": "Simple",
        "value": "var(--DarkPurple), var(--SmartThemeUnderlineColor), var(--DarkPurple), var(--DarkPurple)"
      },
      {
        "label": "Golden",
        "value": "#ffd700, #ffec8b, #fff8dc, #ffd700, #daa520, #b8860b, #daa520, #ffd700, #ffec8b, #fff8dc, #ffd700"
      }
    ]
  },
  {
    "type": "select",
    "varId": "favoriteFrame",
    "displayText": "Favorite frame color",
    "default": "#ffd700, #ffec8b, #fff8dc, #ffd700, #daa520, #b8860b, #daa520, #ffd700, #ffec8b, #fff8dc, #ffd700",
    "options": [
      {
        "label": "Rainbow",
        "value": "#f5c2e7, #f38ba8, #eba0ac, #fab387, #f9e2af, #a6e3a1, #94e2d5, #89dceb, #74c7ec, #89b4fa, #b4befe, #cba6f7, #f5c2e7"
      },
      {
        "label": "Simple",
        "value": "var(--DarkPurple), var(--SmartThemeUnderlineColor), var(--DarkPurple), var(--DarkPurple)"
      },
      {
        "label": "Golden",
        "value": "#ffd700, #ffec8b, #fff8dc, #ffd700, #daa520, #b8860b, #daa520, #ffd700, #ffec8b, #fff8dc, #ffd700"
      }
    ]
  },
  {
    "type": "select",
    "varId": "frameAnimation",
    "displayText": "Frame animation",
    "default": "running",
    "options": [
      {
        "label": "Animated",
        "value": "running"
      },
      {
        "label": "Static",
        "value": "paused"
      }
    ]
  }
]
}

body {
  font-family: var(--mainFont);
  font-weight: 500;
}

:root{
  --crimson70a: rgba(235, 160, 172, 0.7);
  --fullred: rgba(243, 139, 168, 1);
  --warning: rgba(243, 139, 168, 0.9);
  --okGreen70a: rgba(166, 227, 161, 0.7);
}

/* NOTEBOOK */

#notebookPanel .react-tabs__tab--selected {
  color: var(--DarkPurple) !important;
}

.ql-snow .ql-stroke {
  stroke: var(--SmartThemeEmColor) !important;
}
